// Rendered as a SwiftUI Shape (flattened from the official Discord logo path,
// viewBox 0 0 24 24, normalised to 0...1) so it never depends on an asset
// catalog entry that might fail to compile. Even-odd fill punches the two eyes.

import SwiftUI

struct DiscordLogoShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        add(Self.body, to: &p, in: rect)
        add(Self.eyeL, to: &p, in: rect)
        add(Self.eyeR, to: &p, in: rect)
        return p
    }

    private func add(_ pts: [CGPoint], to path: inout Path, in rect: CGRect) {
        guard let first = pts.first else { return }
        func map(_ q: CGPoint) -> CGPoint {
            CGPoint(x: rect.minX + q.x * rect.width, y: rect.minY + q.y * rect.height)
        }
        path.move(to: map(first))
        for q in pts.dropFirst() { path.addLine(to: map(q)) }
        path.closeSubpath()
    }

    private static func parse(_ s: String) -> [CGPoint] {
        s.split(separator: " ").compactMap { pair in
            let xy = pair.split(separator: ",")
            guard xy.count == 2, let x = Double(xy[0]), let y = Double(xy[1]) else { return nil }
            return CGPoint(x: x, y: y)
        }
    }

