/// Discord logo tile: the Clyde mark centered on a blurple rounded circle.
struct DiscordGlyph: View {
    var body: some View {
        DiscordLogoShape()
            .fill(.white, style: FillStyle(eoFill: true))
            .aspectRatio(1, contentMode: .fit)
    }
}
